INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'listening', 'Begrüßungen', 'Greetings', 'Lerne grundlegende Begrüßungen auf Deutsch', 'Learn basic greetings in German',
'{"type":"listen_and_choose","instructions":"Höre dir die Begrüßung an und wähle das richtige Bild.","exercises":[{"prompt":"Hallo! Wie geht es dir?","options":["Eine winkende Person","Eine schlafende Person","Jemand beim Essen","Jemand beim Laufen"],"correct":0,"hint":"Das ist eine freundliche Begrüßung","hint_translation":"This is a friendly greeting"},{"prompt":"Auf Wiedersehen! Bis später!","options":["Jemand kommt an","Eine winkende Person (beim Abschied)","Jemand sitzt","Jemand kocht"],"correct":1,"hint":"Jemand geht weg","hint_translation":"Someone is going away"},{"prompt":"Guten Morgen!","options":["Nachthimmel","Sonnenaufgang","Regentag","Sonnenuntergang"],"correct":1,"hint":"Denke daran, wenn du aufwachst","hint_translation":"Think of this when you wake up"},{"prompt":"Gute Nacht! Schlaf gut!","options":["Sonniger Day","Person bei der Arbeit","Mond und Sterne","Spielplatz"],"correct":2,"hint":"Zeit zum Schlafen","hint_translation":"Time to sleep"},{"prompt":"Freut mich, Sie kennenzulernen!","options":["Zwei Personen schütteln Hände","Eine Person allein","Eine wütende Person","Jemand läuft"],"correct":0,"hint":"Jemanden neu treffen","hint_translation":"Meeting someone new"}]}', 1),

('de', 'A1', 'listening', 'Zahlen 1 bis 10', 'Numbers 1 to 10', 'Höre und lerne die Zahlen von eins bis zehn', 'Listen and learn the numbers from one to ten',
'{"type":"listen_and_choose","instructions":"Höre die Zahl und wähle die richtige Ziffer.","exercises":[{"prompt":"Drei","options":["1","3","5","7"],"correct":1,"hint":"Kommt nach zwei","hint_translation":"Comes after two"},{"prompt":"Sieben","options":["4","6","7","9"],"correct":2,"hint":"Kommt nach sechs","hint_translation":"Comes after six"},{"prompt":"Eins","options":["1","2","10","8"],"correct":0,"hint":"Die allererste Zahl","hint_translation":"The very first number"},{"prompt":"Zehn","options":["2","5","8","10"],"correct":3,"hint":"Zwei Hände voll Finger","hint_translation":"Two hands full of fingers"},{"prompt":"Fünf","options":["3","5","4","6"],"correct":1,"hint":"Genau in der Mitte","hint_translation":"Right in the middle"}]}', 2),

('de', 'A1', 'listening', 'Farben um uns herum', 'Colors Around Us', 'Höre und identifiziere Farben', 'Listen and identify colors',
'{"type":"listen_and_choose","instructions":"Höre den Farbnamen und wähle die richtige Farbe.","exercises":[{"prompt":"Rot","options":["🔴","🔵","🟢","🟡"],"correct":0,"hint":"Die Farbe der Feuerwehr","hint_translation":"The color of the fire truck"},{"prompt":"Blau","options":["🟠","🔵","🟣","🔴"],"correct":1,"hint":"Die Farbe des Himmels","hint_translation":"The color of the sky"},{"prompt":"Grün","options":["🟡","🔴","🟢","🔵"],"correct":2,"hint":"Die Farbe von Gras","hint_translation":"The color of grass"},{"prompt":"Gelb","options":["🟢","🟣","🔴","🟡"],"correct":3,"hint":"Die Farbe der Sonne","hint_translation":"The color of the sun"},{"prompt":"Orange","options":["🟠","🔵","🟢","🟡"],"correct":0,"hint":"Eine Frucht hat diesen Namen auch","hint_translation":"A fruit has this name too"}]}', 3),

('de', 'A1', 'listening', 'Meine Familie', 'My Family', 'Höre und lerne die Namen der Familienmitglieder', 'Listen and learn the names of family members',
'{"type":"listen_and_choose","instructions":"Höre zu und wähle die beschriebene Person.","exercises":[{"prompt":"Das ist meine Mutter. Sie ist sehr nett.","options":["👩 Mutter","👨 Vater","👦 Bruder","👧 Schwester"],"correct":0,"hint":"Ein weiblicher Elternteil","hint_translation":"A female parent"},{"prompt":"Mein Vater kocht gerne.","options":["👧 Schwester","👦 Bruder","👨 Vater","👩 Mutter"],"correct":2,"hint":"Ein männlicher Elternteil","hint_translation":"A male parent"},{"prompt":"Ich habe eine kleine Schwester.","options":["👦 Bruder","👨 Vater","👩 Mutter","👧 Schwester"],"correct":3,"hint":"Ein junges weibliches Geschwisterkind","hint_translation":"A young female sibling"},{"prompt":"Mein Bruder spielt Fußball.","options":["👦 Bruder","👧 Schwester","👩 Mutter","👨 Vater"],"correct":0,"hint":"Ein männliches Geschwisterkind","hint_translation":"A male sibling"},{"prompt":"Oma erzählt uns Geschichten.","options":["👨 Vater","👩 Mutter","👵 Oma","👦 Bruder"],"correct":2,"hint":"Die Mutter deiner Eltern","hint_translation":"The mother of your parents"}]}', 4),

('de', 'A1', 'listening', 'Tiere, die ich kenne', 'Animals I Know', 'Höre Tiernamen und Geräusche', 'Listen to animal names and sounds',
'{"type":"listen_and_choose","instructions":"Höre zu und wähle das richtige Tier.","exercises":[{"prompt":"Die Katze sagt miau.","options":["🐱","🐶","🐦","🐸"],"correct":0,"hint":"Ein kleines Haustier mit weichem Fell","hint_translation":"A small pet with soft fur"},{"prompt":"Der Hund bellt.","options":["🐱","🐶","🐟","🐘"],"correct":1,"hint":"Ein treues Haustier, das Stöckchen holt","hint_translation":"A faithful pet that fetches sticks"},{"prompt":"Schau mal, der große Elefant!","options":["🐁","🐦","🐘","🐟"],"correct":2,"hint":"Das größte Landsäugetier","hint_translation":"The largest land mammal"},{"prompt":"Der Vogel singt.","options":["🐸","🐦","🐱","🐶"],"correct":1,"hint":"Er hat Flügel und Federn","hint_translation":"It has wings and feathers"},{"prompt":"Der Fisch schwimmt im Wasser.","options":["🐦","🐱","🐶","🐟"],"correct":3,"hint":"Er lebt unter Wasser","hint_translation":"It lives under water"}]}', 5);

