INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'writing', 'Buchstaben tippen', 'Typing Letters', 'Einzelne Buchstaben tippen üben', 'Practice typing individual letters',
'{"type":"type_word","instructions":"Tippe den Buchstaben, den du siehst.","exercises":[{"prompt":"Tippe: A","expected":"A","hint":"Der erste Buchstabe","hint_translation":"The first letter"},{"prompt":"Tippe: B","expected":"B","hint":"Der zweite Buchstabe","hint_translation":"The second letter"},{"prompt":"Tippe: C","expected":"C","hint":"Das Wort Clown beginnt damit","hint_translation":"The word Clown starts with this"},{"prompt":"Tippe: D","expected":"D","hint":"Das Wort Dino beginnt damit","hint_translation":"The word Dino starts with this"},{"prompt":"Tippe: E","expected":"E","hint":"Das Wort Elefant beginnt damit","hint_translation":"The word Elephant starts with this"}]}', 1),

('de', 'A1', 'writing', 'Wörter buchstabieren', 'Spelling Words', 'Kurze Wörter richtig schreiben', 'Write short words correctly',
'{"type":"type_word","instructions":"Höre das Wort und tippe es richtig.","exercises":[{"prompt":"katze","expected":"katze","hint":"🐱 Fünf Buchstaben, beginnt mit K","hint_translation":"Five letters, starts with K"},{"prompt":"hund","expected":"hund","hint":"🐶 Vier Buchstaben, beginnt mit H","hint_translation":"Four letters, starts with H"},{"prompt":"sonne","expected":"sonne","hint":"☀️ Fünf Buchstaben, beginnt mit S","hint_translation":"Five letters, starts with S"},{"prompt":"rot","expected":"rot","hint":"🔴 Drei Buchstaben, eine Farbe","hint_translation":"Three letters, a color"},{"prompt":"groß","expected":"groß","hint":"Das Gegenteil von klein","hint_translation":"The opposite of small"}]}', 2),

('de', 'A1', 'writing', 'Worträtsel', 'Word Puzzles', 'Buchstaben ordnen, um Wörter zu bilden', 'Arrange letters to form words',
'{"type":"unscramble","instructions":"Die Buchstaben sind vertauscht! Tippe das richtige Wort.","exercises":[{"scrambled":"atkez","expected":"katze","hint":"🐱 Ein Haustier, das miau sagt","hint_translation":"A pet that says meow"},{"scrambled":"neons","expected":"sonne","hint":"☀️ Sie scheint am Himmel","hint_translation":"It shines in the sky"},{"scrambled":"faple","expected":"apfel","hint":"🍎 Eine rote Frucht","hint_translation":"A red fruit"},{"scrambled":"hchu","expected":"buch","hint":"📖 Man kann es lesen","hint_translation":"You can read it"},{"scrambled":"chisf","expected":"fisch","hint":"🐟 Er schwimmt im Wasser","hint_translation":"It swims in water"}]}', 3),

('de', 'A1', 'writing', 'Wort vervollständigen', 'Completing Words', 'Fehlende Buchstaben einfüllen', 'Fill in missing letters',
'{"type":"fill_letters","instructions":"Einige Buchstaben fehlen. Tippe das ganze Wort.","exercises":[{"partial":"k_tze","expected":"katze","hint":"🐱 Ein flauschiges Tier","hint_translation":"A fluffy animal"},{"partial":"h_nd","expected":"hund","hint":"🐶 Ein treues Tier","hint_translation":"A faithful animal"},{"partial":"b__h","expected":"buch","hint":"📖 Man liest darin","hint_translation":"You read in it"},{"partial":"h__s","expected":"haus","hint":"🏠 Wo man wohnt","hint_translation":"Where you live"},{"partial":"bl__e","expected":"blume","hint":"🌸 Wächst im Garten","hint_translation":"Grows in the garden"}]}', 4),

('de', 'A1', 'writing', 'Satz schreiben', 'Writing Sentences', 'Einfache Sätze genau abtippen', 'Type simple sentences exactly',
'{"type":"copy_sentence","instructions":"Lies den Satz und tippe ihn genau so.","exercises":[{"sentence":"Ich bin glücklich.","expected":"Ich bin glücklich.","hint":"Drei Wörter und ein Punkt","hint_translation":"Three words and a period"},{"sentence":"Die Katze ist groß.","expected":"Die Katze ist groß.","hint":"Vier Wörter über eine Katze","hint_translation":"Four words about a cat"},{"sentence":"Ich mag Rot.","expected":"Ich mag Rot.","hint":"Drei Wörter über eine Farbe","hint_translation":"Three words about a color"},{"sentence":"Sie hat einen Hund.","expected":"Sie hat einen Hund.","hint":"Vier Wörter über ein Haustier","hint_translation":"Four words about a pet"},{"sentence":"Wir gehen zur Schule.","expected":"Wir gehen zur Schule.","hint":"Vier Wörter über einen Ort","hint_translation":"Four words about a place"}]}', 5);

