('de', 'A2', 'speaking', 'Im Restaurant', 'At the Restaurant', 'Übe, Essen zu bestellen', 'Practice ordering food',
'{"type":"speak_and_compare","instructions":"Stell dir vor, du bist im Restaurant.","exercises":[{"prompt":"Die Speisekarte, bitte.","expected":"die speisekarte bitte","hint":"Nach der Karte fragen"},{"prompt":"Ich möchte eine Pizza, bitte.","expected":"ich möchte eine pizza bitte","hint":"Essen bestellen"},{"prompt":"Ein Wasser, bitte.","expected":"ein wasser bitte","hint":"Ein Getränk bestellen"},{"prompt":"Was kostet das?","expected":"was kostet das","hint":"Nach dem Preis fragen"},{"prompt":"Danke, es war sehr lecker!","expected":"danke es war sehr lecker","hint":"Das Essen loben"}]}', 1),

('de', 'A2', 'reading', 'Eine kurze Geschichte', 'A Short Story', 'Eine einfache Geschichte verstehen', 'Understand a simple story',
'{"type":"read_and_choose","instructions":"Lies die Geschichte und antworte.","passage":"Tom steht um sieben Uhr auf. Er isst Toast und trinkt Orangensaft zum Frühstück. Dann geht er mit seinem Freund Sam zur Schule. In der Schule lernen sie Mathe und Bio.","exercises":[{"question":"Was isst Tom zum Frühstück?","options":["Toast","Müsli","Eier","Pfannkuchen"],"correct":0},{"question":"Mit wem geht Tom zur Schule?","options":["Lehrer","Mutter","Freund Sam","Allein"],"correct":2},{"question":"Wann steht Tom auf?","options":["6 Uhr","7 Uhr","8 Uhr","9 Uhr"],"correct":1},{"question":"Was lernt er?","options":["Sport","Mathe","Kunst","Musik"],"correct":1},{"question":"Was trinkt er?","options":["Wasser","Milch","Saft","Tee"],"correct":2}]}', 1),

