'{"type":"fill_blank_type","instructions":"Tippe das fehlende Wort.","exercises":[{"sentence":"Ich ___ jeden Tag zur Schule.","expected":"gehe","hint":"Verb für laufen","hint_translation":"Verb for walking/going"},{"sentence":"Sie ___ gestern ein rotes Kleid.","expected":"trug","hint":"Vergangenheit von tragen","hint_translation":"Past tense of wearing"},{"sentence":"Wir ___ um sieben zu Abend.","expected":"essen","hint":"Was man mit Essen macht","hint_translation":"What you do with food"},{"sentence":"Er ___ seine Hausaufgaben.","expected":"macht","hint":"Eine Tätigkeit ausführen","hint_translation":"Perform an activity"},{"sentence":"Sie ___ im Park.","expected":"spielen","hint":"Spaß haben","hint_translation":"Have fun"}]}', 1);
